class Solution:
    def doesAliceWin(self, s: str) -> bool:
        vowels = {'a', 'e', 'i', 'o', 'u'}
        vowel_count = 0
        for ch in s:
            if ch in vowels:
                vowel_count += 1
        # Alice wins if the total number of vowels is odd
        return vowel_count % 2 == 1
